import React, { useEffect } from 'react';
import { Html5QrcodeScanner } from "html5-qrcode";

const Scanner = () => {
  useEffect(() => {
    const scanner = new Html5QrcodeScanner("reader", { fps: 10, qrbox: 250 });
    
    scanner.render((result) => {
      alert("स्कॅन यशस्वी: " + result);
      scanner.clear(); // स्कॅन झाल्यावर कॅमेरा बंद करा
    }, (error) => {
      // console.warn(error);
    });
  }, []);

  return (
    <div style={{ background: '#000', color: '#fff', padding: '50px', textAlign: 'center', minHeight: '100vh' }}>
      <h1>QR Scanner</h1>
      <p>पेमेंट किंवा प्रोफाइल स्कॅन करण्यासाठी कॅमेरा वापरा.</p>
      <div id="reader" style={{ width: '400px', margin: '20px auto', background: '#fff', color: '#000' }}></div>
    </div>
  );
};

export default Scanner;
